from langchain_anthropic import ChatAnthropic
from langchain_core.messages import SystemMessage, HumanMessage
import json, re

bidder_llm = ChatAnthropic(model="claude-haiku-4-5-20251001")

def make_bidder_agent(agent_id: str, skills: list[str], base_capacity: float):
    """Factory: returns a bidder node with fixed skills and starting capacity."""    # Mutable load state (decreases as agent takes on work)
    load = {"current": base_capacity}

    def bidder_node(state: AuctionState) -> dict:
        if state["current_task_idx"] >= len(state["tasks"]):
            return {}

        task = state["tasks"][state["current_task_idx"]]

        skill_match = len(set(skills) & set(task.required_skills)) / max(len(task.required_skills), 1)
        effective_score = skill_match * load["current"]

        prompt = f"""You are agent {agent_id} with skills: {', '.join(skills)}.
Current capacity: {load['current']:.0%}.
Task: {task.description}
Required skills: {task.required_skills}
Skill match: {skill_match:.0%}, effective bid: {effective_score:.2f}

Should you bid on this task? Give a final bid score 0.0-1.0 and short rationale.
Bid lower if overloaded; 0.0 means you decline.
Reply as JSON: {{"score": 0.75, "rationale": "..."}}"""        
        response = bidder_llm.invoke([
            SystemMessage(content="You are a resource-aware bidding agent."),
            HumanMessage(content=prompt)
        ])

        raw = re.search(r'\{.*?\}', response.content, re.DOTALL)
        bid_data = json.loads(raw.group()) if raw else {"score": effective_score, "rationale": "auto"}

        bid = Bid(
            agent_id=agent_id,
            task_id=task.task_id,
            score=min(max(bid_data["score"], 0.0), 1.0),
            rationale=bid_data["rationale"],
        )
        return {"current_bids": state["current_bids"] + [bid]}

    bidder_node.__name__ = f"bidder_{agent_id}"
    return bidder_node, load  # expose load for winner callback

# Create heterogeneous agents
researcher_node, researcher_load = make_bidder_agent(
    "researcher", ["web_search", "summarization"], base_capacity=0.9
)
coder_node, coder_load = make_bidder_agent(
    "coder", ["python", "debugging", "code_review"], base_capacity=0.7
)
analyst_node, analyst_load = make_bidder_agent(
    "analyst", ["data_analysis", "summarization", "math"], base_capacity=0.8
)
